var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 8시간 경과","JPN":"黒い氾濫の発生から8時間経過","ENG":"8 hours since the Black Flood onset","TWN":"黑色洪災發生8小時後","DEU":"8 hours since the Black Flood onset","FRA":"8 hours since the Black Flood onset"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"아네모네 펀─치!","JPN":"アネモネパ～ンチ！","ENG":"Anemone Puuunch!","TWN":"銀蓮花─拳！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으아아~ 끝이 없슴다!","JPN":"わわっ～キリがないっす！","ENG":"Whoa...! They just keep coming!","TWN":"嗚啊啊～真是沒完沒了啊！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"이대로라면 침식체들이 우리 마을을 몽땅 차지할 검다!","JPN":"このままだと侵食体が村を完全に占領しちゃうっす！","ENG":"At this rate, C.O.s are gonna take over our whole village!","TWN":"再這樣下去，侵蝕體會奪走我們整個村子！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"알고 있습니다. 모네.","JPN":"わかっています、モネ。","ENG":"I know, Mone.","TWN":"我知道，莫妮。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이대로라면 저희를 친절하게 받아주신 마을은 물론…….","JPN":"このままでは、私たちを温かく受け入れてくださった村はもちろん……","ENG":"If this keeps up, not only the village that welcomed us so kindly...","TWN":"這樣下去，不只親切接受我們的村子……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이 섬까지 끔살나게 되겠죠.","JPN":"この島までグッバイです。","ENG":"This whole island's gonna get wiped out.","TWN":"連這座島也會被吞沒吧。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스. 관리국에 지원 요청을 보낸 건 맞습니까?","JPN":"リコリス。確かに管理局に支援を要請したのですか？","ENG":"Lycoris. You did send a support request to the Administration, right?","TWN":"莉克麗絲，妳有向管理局發出支援請求吧？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이러다간… 할머니가 되어버려요?","JPN":"このままじゃ……おばあさんになっちゃいますよ？","ENG":"At this rate... we'll turn into grandmas, you know?","TWN":"照這樣下去……我都要變成老婆婆了？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"당연히 했지!","JPN":"そりゃとっくにしたって！","ENG":"Of course I did!","TWN":"當然有啊！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하지만 그쪽도 사정이 안 좋은 것 같아.","JPN":"でも、あっちも状況がよくないみたいよ。","ENG":"But things look bad on their side too.","TWN":"可是那邊好像也自身難保。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"검은 범람이 발생해서 도시 전역이 난리라더라.","JPN":"黒い氾濫が発生して、都市全域がめちゃくちゃらしくて。","ENG":"The Black Flood hit, and the whole city's in chaos.","TWN":"黑色洪災爆發，整個城市都亂成一團了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어쩌면… 이 섬을 포기해야 할지도…….","JPN":"もしかしたら……この島は放棄しないとダメかも……","ENG":"We might... have to abandon this island...","TWN":"搞不好……我們得放棄這座島了……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"꺅?!","JPN":"きゃっ！？","ENG":"Kyaah?!","TWN":"啊？！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야! 왜 때려?!","JPN":"ちょっと！　なんで叩くのよ！","ENG":"Hey! Why'd you hit me?!","TWN":"喂！你幹嘛打我？！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"맞을 만하니까 때린 겁니다.","JPN":"叩かれて当然です。","ENG":"Because you deserved it.","TWN":"因為妳活該被打。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스, 이곳은 모네가 나고 자란 고향입니다.","JPN":"リコリス、ここはモネが生まれ育った故郷です。","ENG":"Lycoris, this is Mone's hometown.","TWN":"莉克麗絲，這裡是莫妮出生、長大的故鄉。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그리고 편찮으신 메이드장님을 반갑게 받아주신 분들이 계신 곳이기도 하죠.","JPN":"それに、具合が悪いメイド長を喜んで受け入れてくださった方々がいる場所でもあります。","ENG":"And it's where the people who kindly welcomed our ailing Chief Maid live.","TWN":"也是那些好心接納身體欠安的女僕長的居民們所在之處。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런 섬을 포기하고 도망가자고요?","JPN":"そんな島を放棄して、逃げようと言うのですか？","ENG":"And you want us to abandon it and run?","TWN":"妳要說放棄這座島、跟大家一起逃跑？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"돌아가면 메이드장님한테 다 이를 겁니다.","JPN":"帰ったらメイド長に全部いいつけます。","ENG":"If we go back, I'll be reporting everything to the Chief Maid.","TWN":"我回去一定會告訴女僕長。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"나, 나도 버리고 싶어서 그러는 줄 알아?!","JPN":"わ、私だって捨てたくてそう言ってるわけじゃないわよ！","ENG":"D-did you think I want to abandon it?!","TWN":"我、我又不是想丟下大家才這麼說的！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"여기서 싸울 수 있는 사람들을 다 그러모아도 힘들잖아.","JPN":"ここで戦える人を全員かき集めたって無理そうだから。","ENG":"Even if we gather everyone who can fight, it's still too much.","TWN":"就算集合所有能戰鬥的人，還是很吃力啊。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"개죽음당하느니, 사람이라도 다 살리는 선택을 하자는 거야.","JPN":"犬死にするくらいなら、人命だけでも救う選択をしようって言ってるの。","ENG":"Choosing to save people instead of dying stupidly?","TWN":"與其白白送死，不如讓更多人活下來。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그, 그, 그건 모네가 허락할 수 없슴다!","JPN":"そ、そ、それはモネが許さないっす！","ENG":"M-M-Mone can't allow that!","TWN":"莫、莫、莫妮不能接受那種事！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네는 이 섬도 구하고 싶슴다!","JPN":"モネはこの島も救いたいっす！","ENG":"Mone wants to save this island too!","TWN":"莫妮想拯救這座島！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"부모님과 이쁜 추억이 있는 고향을 이대로 넘겨줄 수는 없슴다!","JPN":"両親との思い出が残る故郷を、このまま渡すわけにはいかないっす！","ENG":"I can't just give up the home full of precious memories with my parents!","TWN":"這是有爸媽和珍貴回憶的故鄉，我不想拱手讓出去！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};